const { ProjectClient } = require('magicbell-js');
const fs = require('fs');

async function main() {
  const email = process.env.MAGICBELL_EMAIL || 'test';
  const runId = process.env.ZEALT_RUN_ID || '123';
  const projectToken = process.env.MAGICBELL_PROJECT_TOKEN || 'test_token';

  const recipientEmail = `${email}+${runId}@gmail.com`;

  const magicbell = new ProjectClient({
    apiKey: projectToken,
    apiSecret: process.env.MAGICBELL_PROJECT_SECRET,
  });

  try {
    const broadcast = await magicbell.broadcasts.create({
      title: `Broadcast for run ${runId}`,
      content: 'This is a test broadcast',
      category: 'system-update',
      recipients: [{ email: recipientEmail }],
    });

    console.log(broadcast);
    fs.writeFileSync('/home/user/project/output.log', `Broadcast ID: ${broadcast.id}`);
  } catch (error) {
    console.error('Error:', error);
  }
}

main();

